// rational arithmetic (BigInt numerator/denominator) for exact Bernoulli numbers
function gcd(a,b){ a=a<0n?-a:a; b=b<0n?-b:b; while(b){ [a,b]=[b,a%b]; } return a; }
function rat(n,d=1n){ if(typeof n==='number') n=BigInt(n); if(typeof d==='number') d=BigInt(d);
  if(d<0n){ n=-n; d=-d; } const g=gcd(n<0n?-n:n,d); return [n/g,d/g]; }
function radd(a,b){ return rat(a[0]*b[1]+b[0]*a[1], a[1]*b[1]); }
function rsub(a,b){ return rat(a[0]*b[1]-b[0]*a[1], a[1]*b[1]); }
function rmul(a,b){ return rat(a[0]*b[0], a[1]*b[1]); }
function rdiv(a,b){ return rat(a[0]*b[1], a[1]*b[0]); }
function rneg(a){ return [-a[0], a[1]]; }
function rnum(a){ return Number(a[0])/Number(a[1]); }
function rstr(a){ if(a[1]===1n) return a[0].toString(); return a[0].toString()+'/'+a[1].toString(); }
function fact(n){ let r=1n; for(let i=2n;i<=BigInt(n);i++) r*=i; return r; }
function binom(n,k){ return rat(fact(n)/(fact(k)*fact(n-k)), 1n); }

// Bernoulli via Akiyama–Tanigawa recurrence (convention B1 = -1/2)
const BCACHE = [rat(1n,1n)];
function B(n){
  while(BCACHE.length <= n){
    const m = BCACHE.length;
    // row-by-row: A[0][j] = 1/(j+1); A[i][j] = (i)*(A[i-1][j] - A[i-1][j+1])
    const N = m+1;
    let A = Array.from({length:N},(_,j)=>rat(1n, BigInt(j+1)));
    for(let i=1;i<=m;i++){
      const next = [];
      for(let j=0;j<N-i;j++){
        next.push( rmul( rat(BigInt(i),1n), rsub(A[j], A[j+1]) ) );
      }
      A = next;
    }
    BCACHE.push(A[0]);
  }
  return BCACHE[n];
}

// Faulhaber coefficients: S_m(n) = sum_{j=0..m} c_j n^{m+1-j}
// with c_j = binom(m+1,j) B_j / (m+1). Convention: B_1 = -1/2 (the "modern" one)
// which is compatible with the standard formula.
function faulCoeffs(m){
  const out = [];
  const mp1 = rat(BigInt(m+1),1n);
  for(let j=0;j<=m;j++){
    const c = rdiv( rmul(binom(m+1,j), B(j)), mp1 );
    out.push(c); // coefficient of n^{m+1-j}
  }
  return out;
}
// evaluate polynomial with rational coeffs (descending powers) at integer n (BigInt) -> rational
function evalPoly(coeffs, m, n){
  let acc = rat(0n,1n);
  for(let j=0;j<=m;j++){
    const pw = rat( BigInt(n) ** BigInt(m+1-j), 1n );
    acc = radd(acc, rmul(coeffs[j], pw));
  }
  return acc;
}
// float-valued evaluation for smooth curve drawing (no BigInt)
function evalPolyFloat(coeffs, m, x){
  let acc = 0;
  for(let j=0;j<=m;j++){
    acc += rnum(coeffs[j]) * Math.pow(x, m+1-j);
  }
  return acc;
}
function directSum(m, n){
  let s = 0n;
  for(let k=1n;k<=BigInt(n);k++){
    let p = 1n; for(let i=0;i<m;i++) p *= k;
    s += p;
  }
  return rat(s,1n);
}
function formatPoly(coeffs, m){
  // pretty-print in the variable n
  let parts = [];
  for(let j=0;j<=m;j++){
    const c = coeffs[j];
    if(c[0]===0n) continue;
    const deg = m+1-j;
    const sign = c[0] < 0n ? ' − ' : (parts.length? ' + ' : '');
    const abs = [c[0]<0n?-c[0]:c[0], c[1]];
    let coefStr = abs[1]===1n && abs[0]===1n ? '' : (abs[1]===1n? abs[0].toString() : abs[0].toString()+'/'+abs[1].toString());
    if(coefStr && deg>0) coefStr += '·';
    let nPart = '';
    if(deg===0) nPart = (coefStr? '' : '1');
    else if(deg===1) nPart = 'n';
    else nPart = 'n^'+deg;
    parts.push(sign + coefStr + nPart);
  }
  if(parts.length===0) return '0';
  return parts.join('');
}

const mEl=$('#f-m'), nEl=$('#f-n'), mLbl=$('#f-m-lbl'), nLbl=$('#f-n-lbl'), out=$('#f-out'), svg=$('#f-svg');

function renderChart(m){
  svg.innerHTML='';
  const W=620, H=260, padL=50, padR=20, padT=14, padB=30;
  const coeffs = faulCoeffs(m);
  // evaluate S_m(n) on n=0..Nmax numerically
  const Nmax = 12;
  const xs = [];
  const ys = [];
  for(let n=0;n<=Nmax;n++){
    const v = rnum(evalPoly(coeffs, m, n));
    xs.push(n); ys.push(v);
  }
  const yMax = Math.max(1, ys[ys.length-1]);
  const xToPix = n => padL + (n/Nmax)*(W-padL-padR);
  const yToPix = y => (H-padB) - (y/yMax)*(H-padT-padB);
  // axis
  svg.appendChild(SVG('line',{x1:padL,y1:H-padB,x2:W-padR,y2:H-padB,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:padL,y1:padT,x2:padL,y2:H-padB,stroke:'var(--line)'}));
  // ticks
  for(let n=0;n<=Nmax;n+=2){
    const x = xToPix(n);
    svg.appendChild(SVG('line',{x1:x,y1:H-padB,x2:x,y2:H-padB+4,stroke:'var(--mute)'}));
    const t=SVG('text',{x:x,y:H-padB+16,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent = n; svg.appendChild(t);
  }
  const xLabel = SVG('text',{x:(padL+(W-padR))/2, y:H-6, 'text-anchor':'middle','font-size':11, fill:'var(--mute)'});
  xLabel.textContent = 'n'; svg.appendChild(xLabel);
  // bars for direct sum (integer n)
  const bw = Math.max(4,(W-padL-padR)/Nmax * 0.35);
  for(let n=1;n<=Nmax;n++){
    const x = xToPix(n), y = yToPix(ys[n]);
    svg.appendChild(SVG('rect',{x:x-bw/2,y:y,width:bw,height:(H-padB)-y, fill:'rgba(88,196,221,0.55)',stroke:'var(--blue)','stroke-width':1}));
  }
  // curve of polynomial
  const curvePts = [];
  const resolution = 200;
  for(let i=0;i<=resolution;i++){
    const t = i/resolution * Nmax;
    const v = evalPolyFloat(coeffs, m, t);
    curvePts.push([xToPix(t), yToPix(v)]);
  }
  const d = curvePts.map((p,i)=>(i===0?'M':'L')+p[0]+' '+p[1]).join(' ');
  svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  // highlight selected n
  const nSel = parseInt(nEl.value,10);
  if(nSel <= Nmax){
    const xs2 = xToPix(nSel), ys2 = yToPix(ys[nSel]);
    svg.appendChild(SVG('circle',{cx:xs2,cy:ys2,r:5,fill:'var(--pink)',stroke:'#fff','stroke-width':1.3}));
  }
}

function update(){
  const m = parseInt(mEl.value,10), n = parseInt(nEl.value,10);
  mLbl.textContent = 'm = '+m;
  nLbl.textContent = 'n = '+n;
  const coeffs = faulCoeffs(m);
  const polyVal = evalPoly(coeffs, m, n);
  const directVal = directSum(m, n);
  const match = polyVal[0]*directVal[1] === directVal[0]*polyVal[1];
  out.textContent =
    `S_${m}(n) = (1/${m+1})·Σ_{j=0..${m}} C(${m+1},j)·B_j·n^{${m+1}-j}\n\n`+
    `S_${m}(n) = ${formatPoly(coeffs,m)}\n\n`+
    `at n=${n}:\n`+
    `  Faulhaber polynomial = ${rstr(polyVal)}  ≈ ${rnum(polyVal)}\n`+
    `  direct Σ_{k=1..${n}} k^${m} = ${rstr(directVal)}\n`+
    `  ${match ? '✓ exact agreement' : '✗ MISMATCH (bug!)'}`;
  renderChart(m);
}
mEl.addEventListener('input', update);
nEl.addEventListener('input', update);
update();

