const MAX_TABLE = 12;
const tbody = $('#b-table tbody');
for(let n=0;n<=MAX_TABLE;n++){
  const tr = document.createElement('tr');
  const b = B(n);
  const num = rnum(b);
  tr.innerHTML = `<td>${n}</td><td>${rstr(b)}</td><td class="num">${num.toExponential(4)}</td>`;
  tbody.appendChild(tr);
}

const tEl=$('#b-t'), tLbl=$('#b-t-lbl'), NEl=$('#b-N'), NLbl=$('#b-N-lbl'), out=$('#b-out');
function partial(t, N){
  // sum_{n=0..N} B_n t^n / n!
  let s = 0;
  for(let n=0;n<=N;n++){
    const bn = rnum(B(n));
    s += bn * Math.pow(t,n) / Number(fact(n));
  }
  return s;
}
function trueVal(t){
  if(Math.abs(t) < 1e-10) return 1;
  return t / (Math.exp(t) - 1);
}
function update(){
  const t = parseFloat(tEl.value), N = parseInt(NEl.value,10);
  tLbl.textContent = 't = '+t.toFixed(2);
  NLbl.textContent = 'N = '+N;
  const p = partial(t, N);
  const tr = trueVal(t);
  const err = Math.abs(p - tr);
  out.textContent =
    `partial sum Σ_{n=0..${N}} B_n t^n/n! at t=${t.toFixed(3)}:\n`+
    `  ≈ ${p.toFixed(10)}\n\n`+
    `true value t/(e^t − 1):\n`+
    `  = ${tr.toFixed(10)}\n\n`+
    `|error| = ${err.toExponential(3)}\n`+
    `(radius of convergence is 2π ≈ 6.28 — try |t| > 6.28 to see divergence)`;
}
tEl.addEventListener('input', update);
NEl.addEventListener('input', update);
update();

