const nEl=$('#e-n'), nLbl=$('#e-n-lbl'), KEl=$('#e-K'), KLbl=$('#e-K-lbl'), out=$('#e-out'), svg=$('#e-svg');

function chart(){
  svg.innerHTML='';
  const W=620, H=220, padL=50, padR=20, padT=14, padB=30;
  const nMax=30;
  const K = parseInt(KEl.value,10);
  // error curves vs n
  const emErr = [], logErr = [];
  for(let n=3;n<=nMax;n++){
    const hx = harmonicExact(n);
    emErr.push([n, Math.max(1e-18, Math.abs(hx - eulerMaclaurinH(n,K)))]);
    logErr.push([n, Math.max(1e-18, Math.abs(hx - Math.log(n)))]);
  }
