    const t = SVG('text',{x:padL-6,y:y+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
    t.textContent = '10^'+k; svg.appendChild(t);
  }
  // x ticks
  for(let n=3;n<=nMax;n+=6){
    const x = xToPix(n);
    svg.appendChild(SVG('line',{x1:x,y1:H-padB,x2:x,y2:H-padB+4,stroke:'var(--mute)'}));
    const t = SVG('text',{x:x,y:H-padB+16,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent = n; svg.appendChild(t);
  }
  const xL = SVG('text',{x:(padL+(W-padR))/2,y:H-6,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  xL.textContent = 'n'; svg.appendChild(xL);
  // curves
  function plot(curve, color, dash){
    const d = curve.map(([n,e],i)=>(i===0?'M':'L')+xToPix(n)+' '+yToPix(Math.log10(e))).join(' ');
    const p = SVG('path',{d,fill:'none',stroke:color,'stroke-width':1.8});
    if(dash) p.setAttribute('stroke-dasharray',dash);
    svg.appendChild(p);
  }
  plot(logErr, 'var(--pink)', null);
  plot(emErr, 'var(--green)', null);
  // legend
  const L = SVG('g',{});
  const t1=SVG('text',{x:W-padR-180,y:padT+14,'font-size':11,fill:'var(--pink)'}); t1.textContent='|H_n − ln n|';
  const t2=SVG('text',{x:W-padR-180,y:padT+30,'font-size':11,fill:'var(--green)'}); t2.textContent=`|H_n − EM(K=${K})|`;
  L.appendChild(t1); L.appendChild(t2); svg.appendChild(L);
}

