  sLbl.textContent='s = '+s.toFixed(2); NLbl.textContent='N = '+N; KLbl.textContent='K = '+K;
  const naive = naivePartial(s, N);
  const em = emZeta(s, N, K);
  const truth = zetaTrue(s);
  out.textContent =
    `s = ${s.toFixed(3)},  N = ${N},  K = ${K}\n\n`+
    `naïve Σ_{k=1..N} k^{−s}   ≈ ${naive.toFixed(12)}   |err| = ${Math.abs(naive-truth).toExponential(3)}\n`+
